import{_ as n,p as s,q as a,a1 as e}from"./framework-5866ffd3.js";const t={},p=e(`<h1 id="c-指针-pointers" tabindex="-1"><a class="header-anchor" href="#c-指针-pointers" aria-hidden="true">#</a> C 指针 Pointers</h1><h2 id="创建指针" tabindex="-1"><a class="header-anchor" href="#创建指针" aria-hidden="true">#</a> 创建指针</h2><p>您从上一章中了解到，我们可以使用引用运算符 <code>&amp;</code> 获取变量的<strong>内存地址</strong>：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token keyword">int</span> myAge <span class="token operator">=</span> <span class="token number">43</span><span class="token punctuation">;</span> <span class="token comment">// 一个 int 变量</span>

<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%d&quot;</span><span class="token punctuation">,</span> myAge<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 输出 myAge (43) 的值</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%p&quot;</span><span class="token punctuation">,</span> <span class="token operator">&amp;</span>myAge<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 输出myAge的内存地址（0x7ffe5367e044）</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在上面的示例中，<code>&amp;myAge</code> 也称为<strong>指针</strong>。</p><p><strong>指针</strong> 是一个变量，它存储另一个变量的内存地址作为其值。</p><p><strong>指针变量</strong> <strong>指向同一类型的数据类型</strong>（如 <code>int</code>），并使用 <code>*</code> 运算符创建。 您正在使用的变量的地址分配给指针：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token keyword">int</span> myAge <span class="token operator">=</span> <span class="token number">43</span><span class="token punctuation">;</span>    <span class="token comment">// 一个 int 变量</span>
<span class="token keyword">int</span><span class="token operator">*</span> ptr <span class="token operator">=</span> <span class="token operator">&amp;</span>myAge<span class="token punctuation">;</span> <span class="token comment">// 一个名为 ptr 的指针变量，用于存储 myAge 的地址</span>

<span class="token comment">// 输出 myAge (43) 的值</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%d\\n&quot;</span><span class="token punctuation">,</span> myAge<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 输出myAge的内存地址（0x7ffe5367e044）</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%p\\n&quot;</span><span class="token punctuation">,</span> \\<span class="token operator">&amp;</span>myAge<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 用指针（0x7ffe5367e044）输出myAge的内存地址</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%p\\n&quot;</span><span class="token punctuation">,</span> ptr<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="示例说明" tabindex="-1"><a class="header-anchor" href="#示例说明" aria-hidden="true">#</a> 示例说明</h4><p>创建一个名为 <code>ptr</code> 的指针变量，它<strong>指向</strong>一个 <code>int</code> 变量（<code>myAge</code>）。 请注意，指针的类型必须与您正在使用的变量的类型相匹配。</p><p>使用 <code>&amp;</code> 运算符存储 <code>myAge</code> 变量的内存地址，并将其分配给指针。</p><p>现在，<code>ptr</code> 保存了<code>myAge</code> 的内存地址的值。</p><h2 id="取消引用" tabindex="-1"><a class="header-anchor" href="#取消引用" aria-hidden="true">#</a> 取消引用</h2><p>在上面的示例中，我们使用指针变量来获取变量的内存地址（与 <code>&amp;</code> **reference ** 运算符一起使用）。</p><p>但是，您也可以使用 <code>*</code> 运算符（**dereference ** 运算符）获取指针指向的变量的值：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token keyword">int</span> myAge <span class="token operator">=</span> <span class="token number">43</span><span class="token punctuation">;</span>     <span class="token comment">// 变量声明</span>
<span class="token keyword">int</span><span class="token operator">*</span> ptr <span class="token operator">=</span> <span class="token operator">&amp;</span>myAge<span class="token punctuation">;</span>  <span class="token comment">// 指针声明</span>

<span class="token comment">// 参考：用指针输出 myAge 的内存地址（0x7ffe5367e044）</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%p\\n&quot;</span><span class="token punctuation">,</span> ptr<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 取消引用：用指针输出 myAge 的值 (43)</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%d\\n&quot;</span><span class="token punctuation">,</span> <span class="token operator">*</span>ptr<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>请注意，<code>*</code> 符号在这里可能会造成混淆，因为它在我们的代码中做了两件不同的事情：</p><ul><li>在声明 (<code>int* ptr</code>) 中使用时，它会创建一个<strong>指针变量</strong>。</li><li>在声明中不使用时，它充当<strong>解引用运算符</strong>。</li></ul><h2 id="我为什么要学习指针" tabindex="-1"><a class="header-anchor" href="#我为什么要学习指针" aria-hidden="true">#</a> 我为什么要学习指针？</h2><p>指针在 C 语言中很重要，因为它们使您能够操作计算机内存中的数据——这可以减少代码并提高性能。</p><h2 id="三种声明指针变量的方式" tabindex="-1"><a class="header-anchor" href="#三种声明指针变量的方式" aria-hidden="true">#</a> 三种声明指针变量的方式</h2><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token keyword">int</span><span class="token operator">*</span> myNum<span class="token punctuation">;</span> <span class="token comment">// 最常被使用</span>
<span class="token keyword">int</span> <span class="token operator">*</span>myNum<span class="token punctuation">;</span>
<span class="token keyword">int</span> <span class="token operator">*</span> myNum<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,22),o=[p];function c(i,l){return s(),a("div",null,o)}const d=n(t,[["render",c],["__file","c_pointers.html.vue"]]);export{d as default};
